var pivotInteger = function(n) {
    const s = n * (n + 1) / 2;
    const r = Math.round(Math.sqrt(s));
    for (const x of [r - 1, r, r + 1]) {
        if (x >= 1 && x * x === s) return x;
    }
    return -1;
};
